import{_ as a,o as t,c as o,ag as r}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"Settings","description":"","frontmatter":{},"headers":[],"relativePath":"guide/settings.md","filePath":"guide/settings.md","lastUpdated":1772692870000}'),i={name:"guide/settings.md"};function n(l,e,s,d,c,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h1><p>Open Settings by clicking the gear icon in the header. Settings are organized into six sections: Profile, Display, AI Provider, PDF Import Privacy, Security, and Data.</p><h2 id="profile" tabindex="-1">Profile <a class="header-anchor" href="#profile" aria-label="Permalink to &quot;Profile&quot;">​</a></h2><h3 id="biological-sex" tabindex="-1">Biological Sex <a class="header-anchor" href="#biological-sex" aria-label="Permalink to &quot;Biological Sex&quot;">​</a></h3><p>Select male or female. This affects:</p><ul><li>Reference ranges for sex-specific markers (testosterone, estradiol, hematology values)</li><li>PhenoAge calculation (biological age)</li><li>Menstrual cycle tracking, which is only available for female profiles</li></ul><h3 id="date-of-birth" tabindex="-1">Date of Birth <a class="header-anchor" href="#date-of-birth" aria-label="Permalink to &quot;Date of Birth&quot;">​</a></h3><p>Required for PhenoAge (biological age calculation). PhenoAge uses a validated formula from Levine et al. 2018 that computes biological age from 9 biomarkers compared against your chronological age. Without a date of birth, PhenoAge cannot be calculated.</p><h3 id="location-country-and-postal-code" tabindex="-1">Location (Country and Postal Code) <a class="header-anchor" href="#location-country-and-postal-code" aria-label="Permalink to &quot;Location (Country and Postal Code)&quot;">​</a></h3><p>Your location is used to auto-detect a latitude band for the <strong>Light &amp; Circadian</strong> context card. Latitude influences UV exposure availability, seasonal light patterns, and how the AI interprets your circadian context. getbased maps your country and postal code to one of five latitude bands — no precise location is stored or transmitted.</p><h2 id="display" tabindex="-1">Display <a class="header-anchor" href="#display" aria-label="Permalink to &quot;Display&quot;">​</a></h2><h3 id="units-eu-us" tabindex="-1">Units (EU / US) <a class="header-anchor" href="#units-eu-us" aria-label="Permalink to &quot;Units (EU / US)&quot;">​</a></h3><p>Toggle between EU (SI) units and US units:</p><ul><li><strong>EU mode</strong>: mmol/L for glucose and cholesterol, µmol/L for creatinine, etc.</li><li><strong>US mode</strong>: mg/dL for glucose, mg/dL for cholesterol, mg/dL for creatinine, etc.</li></ul><p>The toggle converts all displayed values and reference ranges simultaneously. Your stored data always uses SI units internally.</p><h3 id="date-range-filter" tabindex="-1">Date Range Filter <a class="header-anchor" href="#date-range-filter" aria-label="Permalink to &quot;Date Range Filter&quot;">​</a></h3><p>Control how much history is shown in charts and trend analysis:</p><ul><li><strong>All time</strong> — show every data point ever imported</li><li><strong>Last year</strong>, <strong>Last 6 months</strong>, <strong>Last 3 months</strong> — zoom into recent history</li></ul><p>The selected range applies to charts, trend alerts, and the flagged markers section.</p><h3 id="theme" tabindex="-1">Theme <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;Theme&quot;">​</a></h3><p>Switch between <strong>dark</strong> (default) and <strong>light</strong> mode. The preference is stored locally and applied on every visit.</p><h3 id="time-format" tabindex="-1">Time Format <a class="header-anchor" href="#time-format" aria-label="Permalink to &quot;Time Format&quot;">​</a></h3><p>Choose between <strong>24-hour</strong> and <strong>12-hour</strong> (AM/PM) time display. This affects how meal times appear in the Diet context card.</p><h3 id="guided-tour" tabindex="-1">Guided Tour <a class="header-anchor" href="#guided-tour" aria-label="Permalink to &quot;Guided Tour&quot;">​</a></h3><p>Click <strong>Take a Tour</strong> to replay the 7-step spotlight walkthrough. The tour highlights the drop zone, sidebar navigation, lifestyle context cards, settings, feedback button, and AI chat panel. It&#39;s the same tour that appears automatically on your first visit.</p><h2 id="ai-provider" tabindex="-1">AI Provider <a class="header-anchor" href="#ai-provider" aria-label="Permalink to &quot;AI Provider&quot;">​</a></h2><p>Choose and configure one of four AI backends:</p><table tabindex="0"><thead><tr><th>Provider</th><th>Best for</th></tr></thead><tbody><tr><td><strong>Anthropic</strong></td><td>Best accuracy, direct Claude access</td></tr><tr><td><strong>OpenRouter</strong></td><td>200+ models, pay with card or crypto</td></tr><tr><td><strong>Venice</strong></td><td>Privacy-first, nothing logged on their end</td></tr><tr><td><strong>Local</strong></td><td>Fully local, completely offline, free — Ollama, LM Studio, Jan, etc.</td></tr></tbody></table><p>Each provider has its own panel:</p><ul><li><strong>Anthropic, OpenRouter, Venice</strong>: Paste your API key, select a model from the dropdown. The app fetches available models from the provider automatically when you open Settings.</li><li><strong>Local</strong>: Enter your server URL (default <code>http://localhost:11434</code>), optionally add an API key, and choose from your locally available models. Works with any OpenAI-compatible server.</li></ul><p>See <a href="./ai-providers.html">AI Providers</a> for full setup instructions.</p><h2 id="pdf-import-privacy" tabindex="-1">PDF Import Privacy <a class="header-anchor" href="#pdf-import-privacy" aria-label="Permalink to &quot;PDF Import Privacy&quot;">​</a></h2><p>Shows the current status of PII obfuscation — whether a local AI server is connected and being used, or whether the regex fallback is active.</p><p>Expand the <strong>Configure Local AI</strong> panel to:</p><ul><li>Set the server URL for PII stripping (can be different from the main AI server)</li><li>Select a dedicated model for PII stripping</li><li>Enable debug mode to view a before/after diff of what was replaced in your PDF text</li></ul><p>See <a href="./pii-obfuscation.html">PII Obfuscation</a> for a full explanation of how this works.</p><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><h3 id="encryption" tabindex="-1">Encryption <a class="header-anchor" href="#encryption" aria-label="Permalink to &quot;Encryption&quot;">​</a></h3><p>Enable AES-256-GCM encryption at rest with a passphrase. When enabled, all health data is encrypted before being written to localStorage. See <a href="./encryption.html">Encryption</a> for details.</p><p>Passphrases must meet strength requirements: at least 8 characters, with mixed case and a special character. A live strength meter shows progress as you type.</p><h3 id="change-disable" tabindex="-1">Change / Disable <a class="header-anchor" href="#change-disable" aria-label="Permalink to &quot;Change / Disable&quot;">​</a></h3><p>You can change your passphrase or disable encryption from this section. Disabling encryption decrypts all data back to plaintext.</p><h2 id="data" tabindex="-1">Data <a class="header-anchor" href="#data" aria-label="Permalink to &quot;Data&quot;">​</a></h2><h3 id="backup-restore" tabindex="-1">Backup &amp; Restore <a class="header-anchor" href="#backup-restore" aria-label="Permalink to &quot;Backup &amp; Restore&quot;">​</a></h3><p>View and restore IndexedDB auto-backup snapshots (up to 5 rolling copies). See <a href="./encryption.html#automatic-backups">Encryption</a> for how auto-backup works.</p><h3 id="folder-backup" tabindex="-1">Folder Backup <a class="header-anchor" href="#folder-backup" aria-label="Permalink to &quot;Folder Backup&quot;">​</a></h3><p>Pick a local folder (Proton Drive, Dropbox, NAS) to auto-save backups using the File System Access API. See <a href="./folder-backup.html">Folder Backup</a> for details.</p><h3 id="export-import" tabindex="-1">Export &amp; Import <a class="header-anchor" href="#export-import" aria-label="Permalink to &quot;Export &amp; Import&quot;">​</a></h3><p>Quick access to JSON export (current profile) and data clearing. For full export options including per-client and database bundles, see <a href="./json-export-import.html">JSON Export &amp; Import</a>.</p><h3 id="recommendations" tabindex="-1">Recommendations <a class="header-anchor" href="#recommendations" aria-label="Permalink to &quot;Recommendations&quot;">​</a></h3><p>Toggle supplement and lifestyle recommendations on or off. When enabled, flagged markers show contextual suggestions in the detail modal, chat, and context card health dots.</p><div class="tip custom-block"><p class="custom-block-title">Settings are stored locally</p><p>All settings — API keys, unit preferences, theme, provider choice — are stored in your browser&#39;s localStorage. They never leave your device.</p></div>',52)])])}const g=a(i,[["render",n]]);export{u as __pageData,g as default};
